mapper.select:
select id, waifu_package_code, waifu_package_name, process_code,
       process_name, process_detail_code, process_detail_name,
       position_code, position_name, dept_id, dept_name, allot_type,
       machine_type_code, machine_type_name, rate,
       update_by, update_by_name, update_time, remark, create_by, create_by_name, create_time
from M_WAIFU_PRICE_PROCESS


        and dept_id = #{deptId}


        and waifu_package_code = #{waifuPackageCode}


        and allot_Type = #{allotType}


        and process_Code = #{processCode}


        and position_Code = #{positionCode}


order by CREATE_TIME desc

select id, waifu_package_code, waifu_package_name, process_code,
       process_name, process_detail_code, process_detail_name,
       position_code, position_name, dept_id, dept_name, allot_type,
       machine_type_code, machine_type_name, rate,
       update_by, update_by_name, update_time, remark, create_by, create_by_name, create_time
from M_WAIFU_PRICE_PROCESS


        and dept_id = #{deptId}


        and waifu_package_code = #{waifuPackageCode}


        and allot_Type = #{allotType}


        and process_Code = #{processCode}


        and position_Code = #{positionCode}

update.foreach:
UPDATE M_WAIFU_PRICE_PROCESS SET ID = #{item.id, jdbcType=BIGINT}, WAIFU_PACKAGE_CODE = #{item.waifuPackageCode, jdbcType=VARCHAR}, WAIFU_PACKAGE_NAME = #{item.waifuPackageName, jdbcType=VARCHAR}, PROCESS_CODE = #{item.processCode, jdbcType=VARCHAR}, PROCESS_NAME = #{item.processName, jdbcType=VARCHAR}, PROCESS_DETAIL_CODE = #{item.processDetailCode, jdbcType=VARCHAR}, PROCESS_DETAIL_NAME = #{item.processDetailName, jdbcType=VARCHAR}, POSITION_CODE = #{item.positionCode, jdbcType=VARCHAR}, POSITION_NAME = #{item.positionName, jdbcType=VARCHAR}, DEPT_ID = #{item.deptId, jdbcType=BIGINT}, DEPT_NAME = #{item.deptName, jdbcType=VARCHAR}, ALLOT_TYPE = #{item.allotType, jdbcType=VARCHAR}, MACHINE_TYPE_CODE = #{item.machineTypeCode, jdbcType=VARCHAR}, MACHINE_TYPE_NAME = #{item.machineTypeName, jdbcType=VARCHAR}, RATE = #{item.rate, jdbcType=DECIMAL}, REMARK = #{item.remark, jdbcType=VARCHAR}, UPDATE_BY = #{loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{nowDate,jdbcType=TIMESTAMP}
id = #{item.id,jdbcType=BIGINT}
;
